          // 创建下载链接
          const link = document.createElement('a');
          link.download = `${novel.value?.title || '小说'}-${filename}.png`;
          link.href = dataUrl;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          ElMessage.success('图表已下载');
        } catch (error) {
          console.error('下载图表失败:', error);
