      };
    };

    // 当路由参数变化时重新加载数据
    watch(() => route.params.id, (newId, oldId) => {
      if (newId) {
        try {
          const novelId = parseInt(newId);
          if (isNaN(novelId)) {
            console.error('非法的小说ID:', newId);
            errorMessage.value = '无效的小说ID';
            return;
          }

          // 只有当ID真正变化时才重新加载数据
          if (newId !== oldId) {
            console.log('路由参数变化，加载小说ID:', novelId);
            fetchNovelInfo(novelId);
            fetchAllVisualizationData(novelId);
          }
        } catch (error) {
          console.error('处理路由参数失败:', error);
          errorMessage.value = '处理路由参数失败: ' + (error.message || '未知错误');
        }
      } else {
        console.error('缺少小说ID');
        errorMessage.value = '缺少小说ID，无法加载可视化数据';
      }
    });

    // 组件挂载时加载数据
    onMounted(() => {
      if (route.params.id) {
        try {
          const novelId = parseInt(route.params.id);
          if (isNaN(novelId)) {
            console.error('非法的小说ID:', route.params.id);
            errorMessage.value = '无效的小说ID';
            return;
          }
          console.log('组件挂载，加载小说ID:', novelId);
          fetchNovelInfo(novelId);
          fetchAllVisualizationData(novelId);
        } catch (error) {
          console.error('处理路由参数失败:', error);
          errorMessage.value = '处理路由参数失败: ' + (error.message || '未知错误');
        }
      } else {
        console.error('缺少小说ID');
        errorMessage.value = '缺少小说ID，无法加载可视化数据';
      }
    });
    return {
      novel,
      loading,
      errorMessage,
      keywordData,
      emotionalData,
      structureData,
      characterData,
      loadingKeywords,
      loadingEmotional,
      loadingStructure,
      loadingCharacters,
      activeTab,
      keywordCloudRef,
      plotTrendRef,
      structureChartRef,
      characterNetworkRef,
      goBack,
      refreshData,
      downloadChart,
      toggleFullScreen
    };
  }
};
